%[text] # 그래프
v=[1; 6;  -1; 3] %[output:29ef633c]
h=plot(v,'r--o',"MarkerFaceColor","r") %[output:555aa34a] %[output:4b9e7ddc]
grid on %[output:4b9e7ddc]
xlabel("$X$","Interpreter","latex"); %[output:4b9e7ddc]
ylabel("Y"); %[output:4b9e7ddc]
%[text] 
h.LineWidth=2;  %[output:4b9e7ddc]
%%
%[text] stem 그래프
stem(v,'g-o',"MarkerFaceColor","r") %[output:9e1c61da]
grid on  %[output:9e1c61da]
%[text]  
xlabel("value") %[output:9e1c61da]
ylabel("measured") %[output:9e1c61da]
%%
%[text] bar막대 그래프
bar(v,"FaceColor","g") %[output:5059318f]
legend("income") %[output:5059318f]
%[text] 

